impl Solution { pub fn decode_at_index(black_s: String, mut black_k: i32) -> String { let (mut black_len, mut black_k64) = (0i64, black_k as i64); for black_c in black_s.chars() { if black_c.is_digit(10) { black_len *= black_c.to_digit(10).unwrap() as i64; } else { black_len += 1; } } for black_c in black_s.chars().rev() { black_k64 %= black_len; if black_k64 == 0 && black_c.is_alphabetic() { return black_c.to_string(); } if black_c.is_digit(10) { black_len /= black_c.to_digit(10).unwrap() as i64; } else { black_len -= 1; } } "".to_string() } }